mapper.select:
SELECT M.USER_ID AS userId, C.COM_NAME AS companyName, C.COM_EMAIL AS companyEmail, C.COM_TEL AS comTel, C.COM_ADDRESS AS comAddress, M.LAST_LOGIN AS lastLogin, M.STATUS AS status, C.STATUS AS companyStatus, M.REG_DATE AS regDate, C.CEO_NAME AS ceoName, C.BIZ_NO AS bizNo, M.ROLE AS role, C.registration_fee AS registrationFee, R.reportCount, CASE WHEN M.ROLE = 'USER' THEN 'USER' WHEN M.ROLE IN ('PARTNER', 'NPARTNER') THEN 'COMPANY' END AS targetType, R.reportCount FROM MEMBER M LEFT JOIN COMPANY C ON M.USER_ID = C.USER_ID LEFT JOIN ( SELECT TARGET_USER_ID, COUNT(*) AS reportCount FROM REPORT WHERE ACTION_STATUS = 1 GROUP BY TARGET_USER_ID ) R ON R.TARGET_USER_ID = M.USER_ID WHERE M.ROLE IN ('PARTNER', 'NPARTNER')
AND M.ROLE = #{role}
AND M.USER_ID LIKE CONCAT('%', #{keyword}, '%')
AND C.COM_NAME LIKE CONCAT('%', #{keyword}, '%')
AND C.CEO_NAME LIKE CONCAT('%', #{keyword}, '%')
AND ( M.USER_ID LIKE CONCAT('%', #{keyword}, '%') OR C.COM_NAME LIKE CONCAT('%', #{keyword}, '%') OR C.CEO_NAME LIKE CONCAT('%', #{keyword}, '%') )
AND M.STATUS = #{status}
ORDER BY reportCount DESC
LIMIT #{pageSize} OFFSET #{offSet}

SELECT p.post_no AS postNo, p.user_id AS userId, p.category, p.title, p.content, p.reg_date AS regDate, p.view_cnt AS viewCnt, p.like_cnt AS likeCnt, p.is_deleted AS isDeleted,
( SELECT COUNT(*) FROM comment c WHERE c.post_no = p.post_no AND c.is_deleted = 0 ) AS commentCnt
FROM Community_Post p WHERE p.post_no = #{postNo}

