SELECT * FROM payment
ORDER BY pay_no DESC
LIMIT #{pageSize} OFFSET #{offSet}

SELECT p.product_no AS productNo, p.company_no AS companyNo, p.product_name AS productName, p.product_details AS productDetails, p.original_price AS originalPrice, p.is_active AS isActive, p.img_url AS imgUrl, p.large_category AS largeCategory, p.medium_category AS mediumCategory, p.deposit AS deposit, c.com_name AS comName FROM product p LEFT JOIN company c ON p.company_no = c.company_no
AND ( p.product_name LIKE CONCAT('%', #{keyword}, '%') OR c.com_name LIKE CONCAT('%', #{keyword}, '%') )
AND p.is_active = #{status}
AND LARGE_CATEGORY = #{largeCategory}
AND MEDIUM_CATEGORY = #{mediumCategory}
ORDER BY p.product_no DESC LIMIT #{pageSize} OFFSET #{offSet}

SELECT COUNT(*) FROM product p LEFT JOIN company c ON p.company_no = c.company_no
AND ( p.product_name LIKE CONCAT('%', #{keyword}, '%') OR c.com_name LIKE CONCAT('%', #{keyword}, '%') )
AND p.is_active = #{status}

mapper.update:
UPDATE product
SET is_active = #{isActive}
WHERE product_no = #{productNo}

