SELECT coupon_code AS couponCode, coupon_name AS couponName, discount_rate AS discountRate, issue_type AS issueType, max_issue_cnt AS maxIssueCnt, coupon_type AS couponType FROM coupon WHERE 1=1
AND ( coupon_code LIKE CONCAT('%', #{keyword}, '%') OR coupon_name LIKE CONCAT('%', #{keyword}, '%') )
AND coupon_type = #{status}
ORDER BY coupon_code DESC LIMIT #{pageSize} OFFSET #{offSet}

SELECT COUNT(*) FROM coupon WHERE 1=1
AND ( coupon_code LIKE CONCAT('%', #{keyword}, '%') OR coupon_name LIKE CONCAT('%', #{keyword}, '%') )
AND coupon_type = #{status}

