mapper.select:
SELECT P.pay_no AS payNo, P.amount AS amount, PP.pass_no AS passNo, PP.item_name AS itemName, P.pay_date AS payDate, P.pay_status AS payStatus, PPP.review_cnt AS reviewCnt FROM payment P JOIN payment_pass PP ON P.pay_no = PP.pay_no JOIN pass_product PPP ON PP.pass_no = PPP.pass_no WHERE P.user_id = #{userId}
AND P.pay_status = #{payStatus}
ORDER BY P.pay_date DESC LIMIT #{pageSize} OFFSET #{offSet}

